import json,sys,urllib.request,time
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'; WID='GIhQk0ETziCTYgTB'
def GET(w):
    for a in range(6):
        try: return json.load(urllib.request.urlopen(urllib.request.Request(B+w,headers={'X-N8N-API-KEY':K}),timeout=20))
        except Exception: time.sleep(3)
    return None
d=GET('workflows/'+WID)
if not d: print('GET fail'); sys.exit()
print('Назва:',d.get('name'),'| active:',d.get('active'))
for n in d.get('nodes',[]):
    t=n.get('type','')
    if 'trigger' in t.lower() or 'imap' in t.lower() or 'schedule' in t.lower() or 'cron' in t.lower():
        p=n.get('parameters',{}) or {}
        opts=p.get('options',{}) or {}
        print(' ТРИГЕР:',n.get('name'),'| type:',t)
        print('   постпроцес:',p.get('postProcessAction'),'| mailbox:',p.get('mailbox'),'| options:',{k:opts[k] for k in opts if k in ('customEmailConfig','forceReconnect','allowUnauthorizedCerts')})

PYEOF
